function footer(t) {
  return `<footer class="site-footer softmoon-footer"><div class="section-inner footer-layout"><div><a class="brand-link" href="${t.home}">${logo}<span>Lava Labs</span></a><p>${t.footerText}</p></div><div class="footer-links"><a href="mailto:info@lavalabs.co.kr">Email</a><a href="https://www.instagram.com/lavalabs_official/" target="_blank" rel="noreferrer">Instagram</a><a href="${t.home}">${t.back}</a></div><small>(c) 2026 Lava Labs. All rights reserved.</small></div></footer>`;
}

export function renderSoftmoonBody(locale) {
  const t = text[locale] ?? text.ko;
  const langs = `<div class="language-switcher" aria-label="Language"><a href="/soft_moon/"${locale === "ko" ? " aria-current=\"page\"" : ""}>한국어</a><a href="/en/soft_moon/"${locale === "en" ? " aria-current=\"page\"" : ""}>English</a><a href="/jp/soft_moon/"${locale === "jp" ? " aria-current=\"page\"" : ""}>日本語</a></div>`;
  const sectionNav = `<nav class="softmoon-section-nav" aria-label="${t.sectionNavLabel}">${t.nav.map(([id, label]) => `<a href="#${id}">${label}</a>`).join("")}</nav>`;
  const heroMeta = t.heroMeta.map((item) => `<li>${item}</li>`).join("");
  const principles = t.principles.map(([title, body], index) => `<article><span>0${index + 1}</span><h3>${title}</h3><p>${body}</p></article>`).join("");
  const cards = t.cards.map(([number, title, body, tags]) => `<article><div class="softmoon-card-head"><span>${number}</span><span class="softmoon-card-orbit" aria-hidden="true"></span></div><h3>${title}</h3><p>${body}</p><ul aria-label="Keywords">${tags.map((tag) => `<li>${tag}</li>`).join("")}</ul></article>`).join("");
  const steps = t.steps.map(([number, title, body]) => `<article><span>${number}</span><h3>${title}</h3><p>${body}</p></article>`).join("");
  const statusItems = t.statusItems.map((item) => `<li>${item}</li>`).join("");

  return `<div class="app-shell softmoon-page-shell"><a class="skip-link" href="#main-content">${t.skip}</a><header class="site-header softmoon-site-header"><div class="nav-shell softmoon-nav"><a class="brand-link" href="${t.home}">${logo}<span>Lava Labs</span></a>${sectionNav}${langs}</div></header><main id="main-content"><section class="section softmoon-page-hero"><div class="softmoon-sky" aria-hidden="true"><span></span><span></span><span></span></div><div class="section-inner softmoon-page-hero-grid"><div class="softmoon-hero-copy"><p class="eyebrow">${t.eyebrow}</p><h1>SoftMoon</h1><p class="softmoon-page-statement">${t.statement}</p><p class="softmoon-page-body">${t.body}</p><ul class="softmoon-hero-meta">${heroMeta}</ul><div class="button-row"><a class="button primary" href="/assets/files/softmoon-intro.pdf" download>${t.intro}</a><a class="button secondary" href="#collaboration">${t.contact}</a></div></div><div class="softmoon-page-gallery"><figure><picture><source srcset="/assets/images/lunar-sample-1-720.webp" type="image/webp"><img src="/assets/images/lunar-sample-1.jpg" alt="${t.imageAlts[0]}" width="720" height="900"></picture><figcaption><span>01</span>${t.gallery[0]}</figcaption></figure><figure><picture><source srcset="/assets/images/lunar-sample-2-720.webp" type="image/webp"><img src="/assets/images/lunar-sample-2.jpg" alt="${t.imageAlts[1]}" width="720" height="900"></picture><figcaption><span>02</span>${t.gallery[1]}</figcaption></figure></div></div></section><section class="section softmoon-manifesto-section" id="story"><div class="section-inner softmoon-manifesto"><div><p class="eyebrow">${t.manifestoLabel}</p><h2>${t.manifestoTitle}</h2></div><p>${t.manifestoBody}</p></div></section><section class="section softmoon-principles-section"><div class="section-inner"><div class="section-heading compact"><p class="eyebrow">${t.principlesLabel}</p><h2>${t.principlesTitle}</h2></div><div class="softmoon-principles-grid">${principles}</div></div></section><section class="section softmoon-research-section" id="areas"><div class="section-inner"><div class="softmoon-section-intro"><div class="section-heading compact"><p class="eyebrow">${t.researchLabel}</p><h2>${t.research}</h2></div><p>${t.researchLead}</p></div><div class="softmoon-research-grid">${cards}</div></div></section><section class="section softmoon-process-section" id="process"><div class="section-inner"><div class="softmoon-section-intro"><div class="section-heading compact"><p class="eyebrow">${t.processLabel}</p><h2>${t.processTitle}</h2></div><p>${t.processLead}</p></div><div class="softmoon-process-grid">${steps}</div></div></section><section class="section softmoon-status-section"><div class="section-inner softmoon-status-card"><div><p class="eyebrow">${t.statusLabel}</p><h2>${t.statusTitle}</h2><p>${t.statusBody}</p></div><ul>${statusItems}</ul></div></section><section class="section softmoon-collaboration-section" id="collaboration"><div class="section-inner softmoon-collaboration-card"><div><p class="eyebrow">${t.collaborationLabel}</p><h2>${t.collaborationTitle}</h2><p>${t.collaborationBody}</p></div><div class="softmoon-collaboration-actions"><a class="button primary" href="mailto:info@lavalabs.co.kr?subject=SoftMoon%20Collaboration">${t.mail}</a><a class="button secondary" href="${t.home}#contact">${t.contact}</a><a class="softmoon-back-link" href="${t.home}">${t.back}</a></div></div></section></main>${footer(t)}</div>`;
}
